function smt = fSmoothAryV01(ary,dgr)%% return smoothed array%% smt = fSmoothAryV01(ary,dgr)%% ary: input array% dgr: degree of smoothing% smt: smoothed array%% Kei Nakamura% Created on Sunday, June 29th 2008.% Modified on %% main bodyendN = round((dgr-1)/2);    % edge indexstrtA = ary(1:endN);        % start arayendA = ary(end-endN+1:end);    % and araydgrS = zeros(dgr,4);    % for conveniencedgrS(:,1) = [1:dgr];    % indexdgrS(:,2) = dgrS(:,1)-(dgr+1)/2;   % index with signdgrS((dgr+1)/2:end,3) = dgrS((dgr+1)/2:end,2);  % positive side for SdgrS(1:(dgr-1)/2,4) = dgrS(1:(dgr-1)/2,2);    % negative side for SaryS = zeros(dgr,numel(ary));   % mat for smoothingfor ii=1:dgr    a = dgrS(ii,3);    b = dgrS(ii,4);    c = -dgrS(ii,4);    d = -dgrS(ii,3);        aryS(ii,1+a:end+b) = ary(1+c:end+d);endsmt = sum(aryS)/dgr;smt(1:endN) = strtA;smt(end-endN+1:end) = endA;
